/** UsptTaskTaxitmWctHistDao.insert */
insert into uspt_task_taxitm_wct_hist (
			 task_taxitm_wct_hist_id
			,cnvn_change_req_id
			,confm_task_taxitm_wct_hist_id
			,bsns_year
			,wct_taxitm_id
			,comput_basis_cn
			,sport_budget
			,alotm_cash
			,alotm_acthng
			,creator_id
			,created_dt
		) values (
			 #{taskTaxitmWctHistId}
			,#{cnvnChangeReqId}
			,#{confmTaskTaxitmWctHistId}
			,#{bsnsYear}
			,#{wctTaxitmId}
			,#{computBasisCn}
			,#{sportBudget}
			,#{alotmCash}
			,#{alotmActhng}
			,#{creatorId}
			,#{createdDt}
		)
